use serde::{Deserialize, Serialize};
use std::io::{self, Read};

const PI: f64 = 3.1415926535;

#[derive(Debug, Clone, Deserialize, Serialize)]
pub struct Parameters {
    pub LENGTH1: f64,
    pub RADIUS1: f64,
    pub EPSILON: f64,
    pub AREA1: f64,
    pub Q_PTS: usize,
    pub QUADS: usize,
    pub DIST: f64,
    pub N_PTS: usize,
    pub K_PTS: usize,
    pub A_PTS: usize,
    pub B_PTS: usize,
    pub C_PTS: usize,
    pub D_PTS: usize,
    pub E_PTS: usize,
    pub F_PTS: usize,
    pub G_PTS: usize,
