        return false;
    }
    for i in 0..=n - np {
        let x1 = x[i];
        let y1 = y[i];
        let x2 = x[i + np - 1];
        let y2 = y[i + np - 1];

        let same = realcompare(x1, x2) == EQ && realcompare(y1, y2) == EQ;

        for j in 1..np - 1 {
            let px = x[i + j];
            let py = y[i + j];
